mapper.select:
/* selectAdmin502List */ SELECT ts.srvy_oid , ts.srvy_ttl , ts.srvy_bgng_dt , ts.srvy_end_dt , SUM(CASE WHEN tsr.cmpl_yn = 'Y' THEN 1 ELSE 0 END) AS survey_cmpl_cnt , CASE WHEN CURDATE() < ts.srvy_bgng_dt THEN '조사전' WHEN CURDATE() BETWEEN ts.srvy_bgng_dt AND ts.srvy_end_dt THEN '조사중' WHEN CURDATE() > ts.srvy_end_dt THEN '조사종료' ELSE '알수없음' END AS survey_status FROM ${schema}.srvy ts LEFT JOIN ${schema}.srvy_rspdnt tsr ON tsr.srvy_oid = ts.srvy_oid
AND ts.srvy_oid = #{srvyOid}
AND ts.srvy_ttl LIKE CONCAT('%', #{srvyTtl}, '%')
AND srvy_end_dt >= #{srvyBgngDt}
AND srvy_bgng_dt <= #{srvyEndDt}
AND CURDATE() < ts.srvy_bgng_dt
AND CURDATE() BETWEEN ts.srvy_bgng_dt AND ts.srvy_end_dt
AND CURDATE() > ts.srvy_end_dt
GROUP BY ts.srvy_oid, ts.srvy_ttl, ts.srvy_bgng_dt, ts.srvy_end_dt

mapper.delete:
/* deleteSurveyRespondents */
DELETE FROM ${schema}.srvy_rspdnt
WHERE
	srvy_oid = #{srvyOid}
	AND srvy_rspdnt_oid = #{srvyRspdntOid}
